function showChapterComments() {
    const { java, chapter } = this;
    const url = chapter.url;
    const paramsHtml = '<div class="hidden" id="params">\'' + url + '\'</div>';
    java.showBrowser("", reviewHtmlTemplate.replace("$2", paramsHtml), "window.run=run", '{"heightPercentage":0.8,"expandedCornersRadius":20,"hideFriction":0.9}');
}

function escapeHtml(str) {
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

function fixRelativeUrls(html, origin) {
    if (html == null) return '';
    html = String(html);
    if (!html || !origin) return html;
    return html.replace(/\bsrc="([^"]+)"/g, function(m, url) {
        if (/^https?:\/\//i.test(url) || /^data:/i.test(url)) return m;
        if (url.charAt(0) === '/') return 'src="' + origin + url + '"';
        return 'src="' + origin + '/' + url + '"';
    });
}
function getChapterComments(chapterUrl) {
    var html = this.java.ajax(chapterUrl);
    var doc = org.jsoup.Jsoup.parse(html);
    var commentArr = doc.select("section.comments-section div.comment").toArray();
    if (commentArr.length === 0) return "";
    var originMatch = /^(https?:\/\/[^\/]+)/.exec(chapterUrl);
    var origin = originMatch ? originMatch[1] : '';
    var result = [];
    for (var i = 0; i < commentArr.length; i++) {
        var c = commentArr[i];
        var isRegistered = c.select("span.comment-title a").size() > 0;
        var author = escapeHtml(c.select("span.comment-title").text());
        var floor = escapeHtml(c.select("span.comment-floor").text());
        var date = escapeHtml(c.select("span.comment-meta:not(.comment-floor)").text());
        var quoteEl = c.select("blockquote p");
        var quote = quoteEl.size() > 0 ? fixRelativeUrls(quoteEl.html(), origin) : "";
        var textEl = c.select("p.comment-text");
        var text = textEl.size() > 0 ? fixRelativeUrls(textEl.html(), origin) : "";
        var replyLink = c.select("a.forum_reply");
        var replyData = replyLink.size() > 0 ? escapeHtml(replyLink.attr("data-comment")) : "";
        var authorClass = isRegistered ? "comment-author" : "comment-author-guest";
        var item = '<li class="comment-item">';
        item += '<div class="comment-header"><span class="' + authorClass + '">' + author + '</span><span class="comment-meta">' + floor + ' ' + date + '</span></div>';
        if (quote) item += '<div class="comment-quote">' + quote + '</div>';
        item += '<div class="comment-text">' + text + '</div>';
        if (replyData) {
            item += '<div class="comment-footer"><button class="btn-reply" data-comment="' + replyData + '" data-author="' + author + '" onclick="showReplyForm(this)">回覆</button></div>';
        }
        item += '</li>';
        result.push(item);
    }
    return result.join("");
}
function postForumReply(chapterUrl, content, replyData) {
    var tokenBody;
    try {
        tokenBody = this.java.post(
            chapterUrl,
            'plxf=getAuthToken',
            {'Content-Type': 'application/x-www-form-urlencoded'}
        ).body();
    } catch(e) {
        return JSON.stringify({status: 500, msg: '無法連接伺服器'});
    }
    var tokenMatch = /<JinJing>(.*?)<\/JinJing>/.exec(tokenBody);
    if (!tokenMatch) {
        return JSON.stringify({status: 500, msg: '獲取令牌失敗'});
    }
    var token = tokenMatch[1];
    var originMatch = /^(https?:\/\/[^\/]+)/.exec(chapterUrl);
    var origin = originMatch ? originMatch[1] : source.bookSourceUrl;
    var forumMatch = /\/(\d+)\.html/.exec(chapterUrl);
    if (!forumMatch) {
        return JSON.stringify({status: 500, msg: '無法解析章節ID'});
    }
    var forumId = forumMatch[1];
    var postBody = 'data=forum&forum_id=' + encodeURIComponent(forumId) + '&content=' + encodeURIComponent(content);
    if (replyData) {
        postBody += '&reply=' + encodeURIComponent(replyData);
    }
    var responseBody;
    try {
        responseBody = this.java.post(
            origin + '/inc/forum_reply.php',
            postBody,
            {
                'Content-Type': 'application/x-www-form-urlencoded',
                'Authorization': token
            }
        ).body();
    } catch(e) {
        return JSON.stringify({status: 500, msg: '網路錯誤'});
    }
    return responseBody;
}

